import { useState } from "react";
import { useNavigate } from "react-router-dom";

export default function AddEmployee() {
  const navigate = useNavigate();

  const [form, setForm] = useState({
    firstName: "",
    lastName: "",
    email: "",
    department: "",
    salary: "",
  });

  const [error, setError] = useState("");

  // ≡ƒö╣ Handle Input
  const handleChange = (e: any) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  // ≡ƒö╣ Validation + Submit
  const handleSubmit = (e: any) => {
    e.preventDefault();

    if (!form.firstName || !form.email || !form.department) {
      setError("All fields are required!");
      return;
    }

    if (!form.email.includes("@")) {
      setError("Invalid email!");
      return;
    }

    // ≡ƒöÑ New Employee Object
    const newEmployee = {
      id: Date.now(),
      ...form,
      salary: Number(form.salary),
      isActive: true,
      performanceRating: 4,
      skills: [],
      address: { city: "Unknown", country: "India" },
    };

    console.log("New Employee:", newEmployee);

    // ≡ƒæë Later: send to API / state
    alert("Employee Added Successfully!");

    navigate("/");
  };

  return (
    <div className="flex items-center justify-center min-h-screen bg-gray-100">
      <form
        onSubmit={handleSubmit}
        className="bg-white p-6 rounded shadow w-[400px]"
      >
        <h2 className="text-xl font-bold mb-4">Add Employee</h2>

        {error && <p className="text-red-500 mb-2">{error}</p>}

        <input
          name="firstName"
          placeholder="First Name"
          className="w-full border p-2 mb-2"
          onChange={handleChange}
        />

        <input
          name="lastName"
          placeholder="Last Name"
          className="w-full border p-2 mb-2"
          onChange={handleChange}
        />

        <input
          name="email"
          placeholder="Email"
          className="w-full border p-2 mb-2"
          onChange={handleChange}
        />

        <input
          name="salary"
          placeholder="Salary"
          className="w-full border p-2 mb-2"
          onChange={handleChange}
        />

        <select
          name="department"
          className="w-full border p-2 mb-2"
          onChange={handleChange}
        >
          <option value="">Select Department</option>
          <option value="Engineering">Engineering</option>
          <option value="HR">HR</option>
          <option value="Sales">Sales</option>
        </select>

        <button className="bg-blue-500 text-white w-full p-2 rounded">
          Add Employee
        </button>
      </form>
    </div>
  );
}

import { useState } from "react";
import EmployeeTable from "../components/EmployeeTable";
import { employees } from "../data/employees";

function Home() {
  const [searchTerm, setSearchTerm] = useState("");
  const [department, setDepartment] = useState("");
  const [status, setStatus] = useState("");
  const [highRating, setHighRating] = useState(false);
  const [sortType, setSortType] = useState<"salary" | "date" | "">("");

  const normalizedSearch = searchTerm.trim().toLowerCase();

  const filteredEmployees = employees.filter((emp) => {
    const matchesSearch =
      normalizedSearch.length === 0 ||
      emp.firstName.toLowerCase().includes(normalizedSearch) ||
      emp.lastName.toLowerCase().includes(normalizedSearch) ||
      emp.email.toLowerCase().includes(normalizedSearch);

    return (
      matchesSearch &&
      (department ? emp.department === department : true) &&
      (status ? (status === "active" ? emp.isActive : !emp.isActive) : true) &&
      (highRating ? emp.performanceRating >= 4 : true)
    );
  });

  const sortedEmployees = [...filteredEmployees];

  if (sortType === "salary") {
    sortedEmployees.sort((a, b) => b.salary - a.salary);
  }

  if (sortType === "date") {
    sortedEmployees.sort(
      (a, b) =>
        new Date(b.joiningDate).getTime() -
        new Date(a.joiningDate).getTime()
    );
  }

  const totalEmployees = sortedEmployees.length;
  const activeEmployees = sortedEmployees.filter((emp) => emp.isActive).length;

  const avgSalary =
    sortedEmployees.length > 0
      ? sortedEmployees.reduce((acc, emp) => acc + emp.salary, 0) /
        sortedEmployees.length
      : 0;

  const highestRated =
    sortedEmployees.length > 0
      ? sortedEmployees.reduce((prev, curr) =>
          curr.performanceRating > prev.performanceRating ? curr : prev
        )
      : null;

  return (
    <div className="min-h-screen bg-gray-100 p-6">
      <h1 className="mb-6 text-2xl font-bold">
        Employee Management System
      </h1>

      {/* Filters */}
      <div className="mb-6 flex flex-wrap gap-3">
        <input
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          placeholder="Search..."
          className="rounded border p-2"
        />

        <select value={department} onChange={(e) => setDepartment(e.target.value)} className="border p-2 rounded">
          <option value="">All Departments</option>
          <option value="Engineering">Engineering</option>
          <option value="HR">HR</option>
          <option value="Sales">Sales</option>
          <option value="Marketing">Marketing</option>
          <option value="Finance">Finance</option>
        </select>

        <select value={status} onChange={(e) => setStatus(e.target.value)} className="border p-2 rounded">
          <option value="">All Status</option>
          <option value="active">Active</option>
          <option value="inactive">Inactive</option>
        </select>

        <label className="flex items-center gap-2">
          <input type="checkbox" checked={highRating} onChange={(e) => setHighRating(e.target.checked)} />
          Rating ΓëÑ 4
        </label>

        <select value={sortType} onChange={(e) => setSortType(e.target.value as any)} className="border p-2 rounded">
          <option value="">Sort By</option>
          <option value="salary">Salary</option>
          <option value="date">Joining Date</option>
        </select>
      </div>

      {/* Dashboard */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-6">
        <div className="bg-white p-4 rounded shadow">
          <p>Total: {totalEmployees}</p>
        </div>
        <div className="bg-white p-4 rounded shadow">
          <p>Active: {activeEmployees}</p>
        </div>
        <div className="bg-white p-4 rounded shadow">
          <p>Avg: Γé╣{avgSalary.toFixed(0)}</p>
        </div>
        <div className="bg-white p-4 rounded shadow">
          <p>
            Top: {highestRated ? highestRated.firstName : "N/A"}
          </p>
        </div>
      </div>

      <EmployeeTable employees={sortedEmployees} />
    </div>
  );
}

export default Home;
